import {
  Controller,
  Post,
  Body,
  UseGuards,
  UnauthorizedException,
} from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { UserRole } from '@mrh/types';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard.js';
import { RolesGuard } from '../auth/guards/roles.guard.js';
import { Roles } from '../auth/decorators/roles.decorator.js';
import { RequirePermissions } from '../auth/decorators/permissions.decorator.js';
import { CurrentUser } from '../auth/decorators/current-user.decorator.js';
import { User } from '../entities/user.entity.js';

@Controller('admin/impersonate')
export class AdminImpersonationController {
  constructor(
    private readonly jwtService: JwtService,
    @InjectRepository(User)
    private readonly userRepository: Repository<User>,
  ) {}

  @Post()
  @UseGuards(JwtAuthGuard, RolesGuard)
  @Roles(UserRole.ADMIN)
  @RequirePermissions('impersonate_users')
  async impersonate(
    @CurrentUser() admin: any,
    @Body() dto: { userId: string },
  ) {
    const targetUser = await this.userRepository.findOne({
      where: { id: dto.userId },
    });
    if (!targetUser) {
      throw new UnauthorizedException('Target user not found');
    }

    const payload: Record<string, string> = {
      sub: targetUser.id,
      email: targetUser.email,
      role: targetUser.role,
      originalAdminId: admin.id,
    };
    const accessToken = this.jwtService.sign(payload, { expiresIn: '1h' });

    return { accessToken, user: targetUser };
  }

  @Post('unimpersonate')
  @UseGuards(JwtAuthGuard, RolesGuard)
  @Roles(UserRole.ADMIN)
  @RequirePermissions('impersonate_users')
  async unimpersonate(@CurrentUser() admin: any) {
    if (!admin.originalAdminId) {
      throw new UnauthorizedException('Not currently impersonating');
    }

    const originalAdmin = await this.userRepository.findOne({
      where: { id: admin.originalAdminId },
    });
    if (!originalAdmin) {
      throw new UnauthorizedException('Original admin account not found');
    }

    const payload: Record<string, string> = {
      sub: originalAdmin.id,
      email: originalAdmin.email,
      role: originalAdmin.role,
    };
    const accessToken = this.jwtService.sign(payload);

    return { accessToken, user: originalAdmin };
  }
}

import {
  Controller,
  Get,
  Param,
  UseGuards,
  NotFoundException,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { UserRole } from '@mrh/types';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard.js';
import { RolesGuard } from '../auth/guards/roles.guard.js';
import { Roles } from '../auth/decorators/roles.decorator.js';
import { RequirePermissions } from '../auth/decorators/permissions.decorator.js';
import { User } from '../entities/user.entity.js';
import { StudentProfile } from '../entities/student-profile.entity.js';
import { Lesson } from '../entities/lesson.entity.js';

@Controller('admin/students')
export class AdminStudentsController {
  constructor(
    @InjectRepository(User)
    private readonly userRepository: Repository<User>,
    @InjectRepository(StudentProfile)
    private readonly studentProfileRepository: Repository<StudentProfile>,
    @InjectRepository(Lesson)
    private readonly lessonRepository: Repository<Lesson>,
  ) {}

  @Get()
  @UseGuards(JwtAuthGuard, RolesGuard)
  @Roles(UserRole.ADMIN, UserRole.SUBADMIN)
  @RequirePermissions('manage_students')
  async getAllStudents() {
    const students = await this.userRepository.find({
      where: { role: UserRole.STUDENT },
      relations: { studentProfile: true },
    });

    const result = await Promise.all(
      students.map(async (student) => {
        const lessonCount = await this.lessonRepository.count({
          where: { studentId: student.id },
        });
        const completedLessons = await this.lessonRepository.count({
          where: { studentId: student.id, status: 'completed' as any },
        });
        return {
          id: student.id,
          firstName: student.firstName,
          lastName: student.lastName,
          email: student.email,
          phone: student.phone,
          avatarUrl: student.avatarUrl,
          isActive: student.isActive,
          isVerified: student.isVerified,
          createdAt: student.createdAt,
          balance: student.studentProfile?.balance ?? 0,
          preferredLanguage: student.studentProfile?.preferredLanguage ?? null,
          totalLessons: lessonCount,
          completedLessons,
        };
      }),
    );

    return result;
  }

  @Get(':id')
  @UseGuards(JwtAuthGuard, RolesGuard)
  @Roles(UserRole.ADMIN, UserRole.SUBADMIN)
  @RequirePermissions('manage_students')
  async getStudent(@Param('id') id: string) {
    const student = await this.userRepository.findOne({
      where: { id, role: UserRole.STUDENT },
      relations: { studentProfile: true },
    });
    if (!student) throw new NotFoundException('Student not found');
    return student;
  }

  @Get(':id/lessons')
  @UseGuards(JwtAuthGuard, RolesGuard)
  @Roles(UserRole.ADMIN, UserRole.SUBADMIN)
  @RequirePermissions('manage_students')
  async getStudentLessons(@Param('id') id: string) {
    const lessons = await this.lessonRepository.find({
      where: { studentId: id },
      relations: { tutor: true, student: true },
      order: { createdAt: 'DESC' },
    });
    return lessons;
  }
}

