import {
  Controller,
  Get,
  Post,
  Put,
  Delete,
  Body,
  Param,
  UseGuards,
} from '@nestjs/common';
import { UserRole } from '@mrh/types';
import { ArticlesService } from './articles.service.js';
import { CreateArticleDto, UpdateArticleDto } from './dto/index.js';
import { CurrentUser } from '../auth/decorators/current-user.decorator.js';
import { Public } from '../auth/decorators/public.decorator.js';
import { Roles } from '../auth/decorators/roles.decorator.js';

@Controller('teacher-training/articles')
export class ArticlesController {
  constructor(private readonly articlesService: ArticlesService) {}

  @Post()
  @Roles(UserRole.ADMIN)
  create(@CurrentUser() user: { id: string }, @Body() dto: CreateArticleDto) {
    return this.articlesService.create(user.id, dto);
  }

  @Public()
  @Get()
  findAllPublished() {
    return this.articlesService.findAllPublished();
  }

  @Get('all')
  @Roles(UserRole.ADMIN)
  findAll() {
    return this.articlesService.findAll();
  }

  @Public()
  @Get(':id')
  findOne(@Param('id') id: string) {
    return this.articlesService.findOne(id);
  }

  @Put(':id')
  @Roles(UserRole.ADMIN)
  update(@Param('id') id: string, @Body() dto: UpdateArticleDto) {
    return this.articlesService.update(id, dto);
  }

  @Delete(':id')
  @Roles(UserRole.ADMIN)
  remove(@Param('id') id: string) {
    return this.articlesService.remove(id);
  }
}

import {
  Controller,
  Post,
  Get,
  Delete,
  Body,
  Res,
  UseGuards,
  HttpCode,
  HttpStatus,
} from '@nestjs/common';
import { Throttle } from '@nestjs/throttler';
import { AuthGuard } from '@nestjs/passport';
import { JwtAuthGuard } from './guards/jwt-auth.guard.js';
import type { Response } from 'express';
import { AuthService } from './auth.service.js';
import { RegisterDto } from './dto/register.dto.js';
import { LoginDto } from './dto/login.dto.js';
import { ForgotPasswordDto } from './dto/forgot-password.dto.js';
import { ResetPasswordDto } from './dto/reset-password.dto.js';
import { Public } from './decorators/public.decorator.js';
import { CurrentUser } from './decorators/current-user.decorator.js';

@Controller('auth')
export class AuthController {
  constructor(private readonly authService: AuthService) {}

  @Public()
  @Throttle({ default: { limit: 5, ttl: 60000 } })
  @Post('register')
  @HttpCode(HttpStatus.CREATED)
  async register(@Body() dto: RegisterDto) {
    return this.authService.register(dto);
  }

  @Public()
  @Throttle({ default: { limit: 5, ttl: 60000 } })
  @Post('login')
  @HttpCode(HttpStatus.OK)
  async login(@Body() dto: LoginDto) {
    return this.authService.login(dto);
  }

  @Post('logout')
  @HttpCode(HttpStatus.OK)
  async logout(@CurrentUser() user: { id: string }) {
    await this.authService.logout(user.id);
    return { message: 'Logged out successfully' };
  }

  @Delete('account')
  @UseGuards(JwtAuthGuard)
  @HttpCode(HttpStatus.OK)
  async deleteAccount(@CurrentUser() user: { id: string }) {
    await this.authService.deleteAccount(user.id);
    return { message: 'Account deleted successfully' };
  }

  @Public()
  @Throttle({ default: { limit: 3, ttl: 3600000 } })
  @Post('forgot-password')
  @HttpCode(HttpStatus.OK)
  async forgotPassword(@Body() dto: ForgotPasswordDto) {
    return this.authService.forgotPassword(dto);
  }

  @Public()
  @Throttle({ default: { limit: 5, ttl: 60000 } })
  @Post('reset-password')
  @HttpCode(HttpStatus.OK)
  async resetPassword(@Body() dto: ResetPasswordDto) {
    return this.authService.resetPassword(dto);
  }

  @Public()
  @Get('google')
  @UseGuards(AuthGuard('google'))
  async googleAuth() {
    // Passport redirects to Google
  }

  @Public()
  @Get('google/callback')
  @UseGuards(AuthGuard('google'))
  async googleCallback(@CurrentUser() profile: any, @Res() res: Response) {
    const result = await this.authService.handleGoogleLogin(profile);
    const frontendUrl = process.env.FRONTEND_URL || 'http://localhost:3000';
    res.redirect(`${frontendUrl}/auth/callback?token=${result.accessToken}`);
  }
}

import { Module } from '@nestjs/common';
import { TypeOrmModule } from '@nestjs/typeorm';
import { JwtModule } from '@nestjs/jwt';
import { PassportModule } from '@nestjs/passport';
import { ConfigModule, ConfigService } from '@nestjs/config';
import { AuthController } from './auth.controller.js';
import { AuthService } from './auth.service.js';
import { JwtStrategy } from './strategies/jwt.strategy.js';
import { GoogleStrategy } from './strategies/google.strategy.js';
import { User } from '../entities/user.entity.js';
import { StudentProfile } from '../entities/student-profile.entity.js';
import { TutorProfile } from '../entities/tutor-profile.entity.js';
import { SubAdminProfile } from '../entities/sub-admin-profile.entity.js';
import { EmailService } from '../services/email.service.js';

@Module({
  imports: [
    TypeOrmModule.forFeature([
      User,
      StudentProfile,
      TutorProfile,
      SubAdminProfile,
    ]),
    PassportModule.register({ defaultStrategy: 'jwt' }),
    JwtModule.registerAsync({
      imports: [ConfigModule],
      inject: [ConfigService],
      useFactory: (configService: ConfigService) => ({
        secret: configService.get<string>('JWT_SECRET')!,
        signOptions: {
          expiresIn:
            (configService.get<string>('JWT_EXPIRES_IN') as any) || '7d',
        },
      }),
    }),
  ],
  controllers: [AuthController],
  providers: [AuthService, JwtStrategy, GoogleStrategy, EmailService],
  exports: [AuthService, JwtModule],
})
export class AuthModule {}

import {
  Injectable,
  BadRequestException,
  ConflictException,
  UnauthorizedException,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { InjectDataSource } from '@nestjs/typeorm';
import { DataSource, Repository } from 'typeorm';
import { JwtService } from '@nestjs/jwt';
import * as bcrypt from 'bcrypt';
import { randomUUID } from 'node:crypto';
import { CourseStatus, UserRole } from '@mrh/types';
import { User } from '../entities/user.entity.js';
import { StudentProfile } from '../entities/student-profile.entity.js';
import { TutorProfile } from '../entities/tutor-profile.entity.js';
import { RegisterDto } from './dto/register.dto.js';
import { LoginDto } from './dto/login.dto.js';
import { ForgotPasswordDto } from './dto/forgot-password.dto.js';
import { ResetPasswordDto } from './dto/reset-password.dto.js';
import { RedisService } from '../redis/redis.service.js';
import { EmailService } from '../services/email.service.js';

function getAdminEmails(): string[] {
  const raw = process.env.ADMIN_EMAILS;
  if (!raw) {
    if (process.env.NODE_ENV === 'production') {
      throw new Error('ADMIN_EMAILS must be set in production');
    }
    return [];
  }
  return raw
    .split(',')
    .map((e) => e.trim().toLowerCase())
    .filter(Boolean);
}

@Injectable()
export class AuthService {
  constructor(
    @InjectRepository(User)
    private readonly userRepository: Repository<User>,
    @InjectDataSource()
    private readonly dataSource: DataSource,
    private readonly jwtService: JwtService,
    private readonly redisService: RedisService,
    private readonly emailService: EmailService,
  ) {}

  async register(dto: RegisterDto) {
    const existing = await this.userRepository.findOne({
      where: { email: dto.email },
    });
    if (existing) {
      throw new ConflictException('Email is already registered');
    }

    const hashedPassword = await bcrypt.hash(dto.password, 12);
    const adminEmails = getAdminEmails();
    const isOwner = adminEmails.includes(dto.email.toLowerCase());

    let role: UserRole;
    if (isOwner) {
      role = UserRole.ADMIN;
    } else if (dto.role === 'tutor') {
      role = UserRole.TUTOR;
    } else {
      role = UserRole.STUDENT;
    }

    try {
      const result = await this.dataSource.transaction(async (manager) => {
        const user = manager.create(User, {
          email: dto.email,
          passwordHash: hashedPassword,
          firstName: dto.firstName,
          lastName: dto.lastName,
          role,
        });
        const savedUser = await manager.save(user);

        if (role === UserRole.TUTOR) {
          const tutorProfile = manager.create(TutorProfile, {
            userId: savedUser.id,
            bio: '',
            specialization: '',
            languages: [],
            hourlyRate: 0,
            balance: 0,
            totalHoursTaught: 0,
            status: CourseStatus.PENDING,
          });
          await manager.save(tutorProfile);
        } else if (role === UserRole.STUDENT) {
          const profile = manager.create(StudentProfile, {
            userId: savedUser.id,
          });
          await manager.save(profile);
        }

        return savedUser;
      });

      const payload: Record<string, string> = {
        sub: result.id,
        email: result.email,
        role: result.role,
      };
      if (result.role === UserRole.STUDENT) {
        const sessionId = randomUUID();
        payload.sessionId = sessionId;
        await this.redisService.set(
          `user_session:${result.id}`,
          sessionId,
          'EX',
          7 * 24 * 60 * 60,
        );
      }

      const accessToken = this.jwtService.sign(payload);

      const { passwordHash, ...safeUser } = result;
      return { accessToken, user: safeUser };
    } catch (error: any) {
      if (error.code === '23505' || error.constraint?.includes('email')) {
        throw new ConflictException('Email is already registered');
      }
      throw error;
    }
  }

  async login(dto: LoginDto) {
    const user = await this.userRepository
      .createQueryBuilder('user')
      .addSelect('user.passwordHash')
      .where('user.email = :email', { email: dto.email })
      .getOne();

    if (!user) {
      throw new UnauthorizedException('Invalid email or password');
    }

    const isPasswordValid = await bcrypt.compare(
      dto.password,
      user.passwordHash,
    );
    if (!isPasswordValid) {
      throw new UnauthorizedException('Invalid email or password');
    }

    const payload: Record<string, string> = {
      sub: user.id,
      email: user.email,
      role: user.role,
    };
    if (user.role === UserRole.STUDENT) {
      const sessionId = randomUUID();
      payload.sessionId = sessionId;
      await this.redisService.set(
        `user_session:${user.id}`,
        sessionId,
        'EX',
        7 * 24 * 60 * 60,
      );
    }

    const accessToken = this.jwtService.sign(payload);

    const { passwordHash, ...safeUser } = user;
    return { accessToken, user: safeUser };
  }

  async getMe(userId: string) {
    const user = await this.userRepository.findOne({
      where: { id: userId },
      relations: {
        tutorProfile: true,
        studentProfile: true,
      },
    });

    if (!user) {
      throw new UnauthorizedException('User not found');
    }

    const { passwordHash, ...safeUser } = user;
    return safeUser;
  }

  async handleGoogleLogin(googleProfile: {
    googleId: string;
    email: string;
    firstName: string;
    lastName: string;
    avatarUrl?: string;
  }) {
    let user = await this.userRepository.findOne({
      where: { googleId: googleProfile.googleId },
    });

    if (!user) {
      const existingByEmail = await this.userRepository.findOne({
        where: { email: googleProfile.email },
      });

      if (existingByEmail) {
        if (
          existingByEmail.googleId &&
          existingByEmail.googleId !== googleProfile.googleId
        ) {
          throw new ConflictException(
            'This email is linked to a different Google account',
          );
        }
        if (!existingByEmail.isVerified && existingByEmail.passwordHash) {
          throw new ConflictException(
            'An account with this email already exists. Please log in with your password first to link Google.',
          );
        }
        existingByEmail.googleId = googleProfile.googleId;
        existingByEmail.isVerified = true;
        if (googleProfile.avatarUrl && !existingByEmail.avatarUrl) {
          existingByEmail.avatarUrl = googleProfile.avatarUrl;
        }
        user = await this.userRepository.save(existingByEmail);
      } else {
        const newUser = this.userRepository.create({
          googleId: googleProfile.googleId,
          email: googleProfile.email,
          firstName: googleProfile.firstName,
          lastName: googleProfile.lastName,
          avatarUrl: googleProfile.avatarUrl,
          role: UserRole.STUDENT,
          isVerified: true,
          passwordHash: await bcrypt.hash(randomUUID(), 12),
        });

        const savedUser = await this.dataSource.transaction(async (manager) => {
          const s = await manager.save(newUser);
          const profile = manager.create(StudentProfile, {
            userId: s.id,
          });
          await manager.save(profile);
          return s;
        });

        user = savedUser;
      }
    }

    const payload: Record<string, string> = {
      sub: user.id,
      email: user.email,
      role: user.role,
    };
    if (user.role === UserRole.STUDENT) {
      const sessionId = randomUUID();
      payload.sessionId = sessionId;
      await this.redisService.set(
        `user_session:${user.id}`,
        sessionId,
        'EX',
        7 * 24 * 60 * 60,
      );
    }

    const accessToken = this.jwtService.sign(payload);

    const { passwordHash, ...safeUser } = user;
    return { accessToken, user: safeUser };
  }

  async forgotPassword(dto: ForgotPasswordDto) {
    const user = await this.userRepository.findOne({
      where: { email: dto.email },
    });

    if (!user) {
      return {
        message: 'If that email is registered, a reset link has been sent',
      };
    }

    const token = randomUUID();
    await this.redisService.set(`reset_token:${token}`, dto.email, 'EX', 3600);

    const frontendUrl = process.env.FRONTEND_URL || 'http://localhost:3000';
    const resetUrl = `${frontendUrl}/reset-password?token=${token}`;

    await this.emailService.sendEmail(
      dto.email,
      'Password Reset - MRH Academy',
      `<p>You requested a password reset.</p>
<p>Click <a href="${resetUrl}">here</a> to reset your password.</p>
<p>This link expires in 1 hour.</p>
<p>If you did not request this, please ignore this email.</p>`,
    );

    return {
      message: 'If that email is registered, a reset link has been sent',
    };
  }

  async resetPassword(dto: ResetPasswordDto) {
    const email = await this.redisService.get(`reset_token:${dto.token}`);
    if (!email) {
      throw new BadRequestException('Invalid or expired reset token');
    }

    const user = await this.userRepository
      .createQueryBuilder('user')
      .addSelect('user.passwordHash')
      .where('user.email = :email', { email })
      .getOne();

    if (!user) {
      throw new BadRequestException('User not found');
    }

    const hashedPassword = await bcrypt.hash(dto.newPassword, 12);
    user.passwordHash = hashedPassword;
    await this.userRepository.save(user);

    await this.redisService.del(`reset_token:${dto.token}`);

    return { message: 'Password reset successfully' };
  }

  async logout(userId: string) {
    await this.redisService.del(`user_session:${userId}`);
  }

  async deleteAccount(userId: string) {
    await this.userRepository.softDelete({ id: userId });
    await this.logout(userId);
  }
}

import { createParamDecorator, ExecutionContext } from '@nestjs/common';

export const CurrentUser = createParamDecorator(
  (data: unknown, ctx: ExecutionContext) => {
    const request = ctx.switchToHttp().getRequest();
    return request.user;
  },
);

import { Injectable, CanActivate, ExecutionContext } from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { ROLES_KEY } from '../decorators/roles.decorator.js';
import { UserRole } from '@mrh/types';

@Injectable()
export class RolesGuard implements CanActivate {
  constructor(private reflector: Reflector) {}

  canActivate(context: ExecutionContext): boolean {
    const requiredRoles = this.reflector.getAllAndOverride<UserRole[]>(
      ROLES_KEY,
      [context.getHandler(), context.getClass()],
    );
    if (!requiredRoles || requiredRoles.length === 0) {
      return true;
    }
    const { user } = context.switchToHttp().getRequest();
    return requiredRoles.includes(user.role);
  }
}

import {
  Injectable,
  CanActivate,
  ExecutionContext,
  UnauthorizedException,
  ServiceUnavailableException,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { RedisService } from '../../redis/redis.service.js';
import { IS_PUBLIC_KEY } from '../decorators/public.decorator.js';

@Injectable()
export class SessionGuard implements CanActivate {
  constructor(
    private readonly redisService: RedisService,
    private readonly reflector: Reflector,
  ) {}

  async canActivate(context: ExecutionContext): Promise<boolean> {
    const isPublic = this.reflector.getAllAndOverride<boolean>(IS_PUBLIC_KEY, [
      context.getHandler(),
      context.getClass(),
    ]);
    if (isPublic) {
      return true;
    }

    const request = context.switchToHttp().getRequest();
    const user = request.user;
    if (!user || !user.id) {
      throw new UnauthorizedException(
        'Session expired or logged in from another device',
      );
    }

    // Non-students (tutor, admin, subadmin) have no sessionId ظ¤ skip Redis check
    if (!user.sessionId) {
      return true;
    }

    const activeSession = await this.redisService.get(
      `user_session:${user.id}`,
    );
    // Redis unset/offline ظ¤ DO NOT allow in dev or prod; it must fail closed
    if (activeSession === null && !this.redisService.connected) {
      throw new ServiceUnavailableException(
        'Session service temporarily unavailable',
      );
    }
    if (activeSession !== user.sessionId) {
      throw new UnauthorizedException(
        'Session expired or logged in from another device',
      );
    }

    return true;
  }
}

import { Injectable, UnauthorizedException } from '@nestjs/common';
import { PassportStrategy } from '@nestjs/passport';
import {
  Strategy,
  VerifyCallback,
  StrategyOptions,
} from 'passport-google-oauth20';
import { ConfigService } from '@nestjs/config';

@Injectable()
export class GoogleStrategy extends PassportStrategy(Strategy, 'google') {
  private readonly googleEnabled: boolean;

  constructor(configService: ConfigService) {
    const clientID = configService.get<string>('GOOGLE_CLIENT_ID');
    const clientSecret = configService.get<string>('GOOGLE_CLIENT_SECRET');
    const callbackURL = configService.get<string>('GOOGLE_CALLBACK_URL');

    const enabled = !!(clientID && clientSecret && callbackURL);

    super({
      clientID: clientID ?? 'missing',
      clientSecret: clientSecret ?? 'missing',
      callbackURL: callbackURL ?? 'http://localhost/missing',
      scope: ['profile', 'email'],
    });

    this.googleEnabled = enabled;
  }

  async validate(
    _accessToken: string,
    _refreshToken: string,
    profile: any,
    _done: VerifyCallback,
  ) {
    if (!this.googleEnabled) {
      throw new UnauthorizedException(
        'Google authentication is not configured',
      );
    }
    const { id, emails, name, photos } = profile;
    return {
      googleId: id,
      email: emails[0].value,
      firstName: name.givenName,
      lastName: name.familyName,
      avatarUrl: photos[0]?.value,
    };
  }
}

import {
  Controller,
  Get,
  Post,
  Put,
  Delete,
  Body,
  Param,
  Query,
  UseGuards,
} from '@nestjs/common';
import { UserRole } from '@mrh/types';
import { AvailabilityService } from './availability.service.js';
import { CreateAvailabilityDto, UpdateAvailabilityDto } from './dto/index.js';
import { CurrentUser } from '../auth/decorators/current-user.decorator.js';
import { Roles } from '../auth/decorators/roles.decorator.js';
import { Public } from '../auth/decorators/public.decorator.js';

@Controller()
export class AvailabilityController {
  constructor(private readonly availabilityService: AvailabilityService) {}

  @Post('tutor/availability')
  @Roles(UserRole.TUTOR)
  create(
    @CurrentUser() user: { id: string },
    @Body() dto: CreateAvailabilityDto,
  ) {
    return this.availabilityService.create(user.id, dto);
  }

  @Get('tutor/availability')
  @Roles(UserRole.TUTOR)
  findMy(@CurrentUser() user: { id: string }) {
    return this.availabilityService.findByTutor(user.id);
  }

  @Put('tutor/availability/:id')
  @Roles(UserRole.TUTOR)
  update(
    @CurrentUser() user: { id: string },
    @Param('id') id: string,
    @Body() dto: UpdateAvailabilityDto,
  ) {
    return this.availabilityService.update(id, user.id, dto);
  }

  @Delete('tutor/availability/:id')
  @Roles(UserRole.TUTOR)
  remove(@CurrentUser() user: { id: string }, @Param('id') id: string) {
    return this.availabilityService.remove(id, user.id);
  }

  @Public()
  @Get('tutors/:tutorId/availability')
  async getTutorAvailability(
    @Param('tutorId') tutorId: string,
    @Query('timezone') timezone?: string,
  ) {
    const slots = await this.availabilityService.findByTutor(tutorId);
    if (!timezone) return slots;

    const tutor = await this.availabilityService.getTutorTimezone(tutorId);
    const tutorTimezone = tutor?.timezone || 'UTC';

    return slots.map((slot) => {
      const converted = this.availabilityService.convertSlot(
        slot.dayOfWeek,
        slot.startTime,
        slot.endTime,
        tutorTimezone,
        timezone,
      );
      return { ...slot, ...converted };
    });
  }
}

import {
  Injectable,
  BadRequestException,
  NotFoundException,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { TutorAvailability } from '../entities/tutor-availability.entity.js';
import { User } from '../entities/user.entity.js';
import { CreateAvailabilityDto, UpdateAvailabilityDto } from './dto/index.js';

@Injectable()
export class AvailabilityService {
  constructor(
    @InjectRepository(TutorAvailability)
    private readonly availabilityRepository: Repository<TutorAvailability>,
    @InjectRepository(User)
    private readonly userRepository: Repository<User>,
  ) {}

  private async checkOverlap(
    tutorId: string,
    dto: CreateAvailabilityDto | UpdateAvailabilityDto,
    excludeId?: string,
  ) {
    const existing = await this.availabilityRepository.find({
      where: { tutorId, dayOfWeek: dto.dayOfWeek! },
    });

    for (const slot of existing) {
      if (excludeId && slot.id === excludeId) continue;
      if (
        this.timesOverlap(
          slot.startTime,
          slot.endTime,
          dto.startTime!,
          dto.endTime!,
        )
      ) {
        throw new BadRequestException(
          'Time slot overlaps with an existing availability',
        );
      }
    }
  }

  private toMinutes(time: string): number {
    const parts = time.split(':');
    return parseInt(parts[0], 10) * 60 + parseInt(parts[1], 10);
  }

  private timesOverlap(
    start1: string,
    end1: string,
    start2: string,
    end2: string,
  ): boolean {
    return (
      this.toMinutes(start1) < this.toMinutes(end2) &&
      this.toMinutes(start2) < this.toMinutes(end1)
    );
  }

  async create(tutorId: string, dto: CreateAvailabilityDto) {
    await this.checkOverlap(tutorId, dto);
    const availability = this.availabilityRepository.create({
      ...dto,
      tutorId,
    });
    return this.availabilityRepository.save(availability);
  }

  findByTutor(tutorId: string) {
    return this.availabilityRepository.find({
      where: { tutorId },
      order: { dayOfWeek: 'ASC', startTime: 'ASC' },
    });
  }

  async update(id: string, tutorId: string, dto: UpdateAvailabilityDto) {
    const availability = await this.availabilityRepository.findOne({
      where: { id, tutorId },
    });
    if (!availability)
      throw new NotFoundException('Availability slot not found');
    if (
      dto.dayOfWeek !== undefined ||
      dto.startTime !== undefined ||
      dto.endTime !== undefined
    ) {
      await this.checkOverlap(tutorId, { ...availability, ...dto }, id);
    }
    Object.assign(availability, dto);
    return this.availabilityRepository.save(availability);
  }

  async remove(id: string, tutorId: string) {
    const availability = await this.availabilityRepository.findOne({
      where: { id, tutorId },
    });
    if (!availability)
      throw new NotFoundException('Availability slot not found');
    return this.availabilityRepository.remove(availability);
  }

  async getTutorTimezone(
    tutorId: string,
  ): Promise<{ timezone: string } | null> {
    const user = await this.userRepository
      .createQueryBuilder('user')
      .select('user.timezone')
      .where('user.id = :id', { id: tutorId })
      .getRawOne();
    return user ? { timezone: user.timezone } : null;
  }

  private getDayName(dayOfWeek: number): string {
    const days = [
      'sunday',
      'monday',
      'tuesday',
      'wednesday',
      'thursday',
      'friday',
      'saturday',
    ];
    return days[dayOfWeek] || 'monday';
  }

  private getReferenceDateInTz(dayOfWeek: number, timezone: string): Date {
    const now = new Date();
    const fmt = new Intl.DateTimeFormat('en-CA', {
      timeZone: timezone,
      weekday: 'long',
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
    });
    const parts = fmt.formatToParts(now);

    const dayMap: Record<string, number> = {
      sunday: 0,
      monday: 1,
      tuesday: 2,
      wednesday: 3,
      thursday: 4,
      friday: 5,
      saturday: 6,
    };

    const todayStr =
      parts.find((p) => p.type === 'weekday')?.value?.toLowerCase() || '';
    const currentDayOfWeek = dayMap[todayStr] ?? now.getDay();

    const year = parts.find((p) => p.type === 'year')?.value;
    const month = parts.find((p) => p.type === 'month')?.value;
    const day = parts.find((p) => p.type === 'day')?.value;

    let diff = dayOfWeek - currentDayOfWeek;
    if (diff < 0) diff += 7;

    const refUtc = Date.UTC(
      Number(year),
      Number(month) - 1,
      Number(day) + diff,
    );
    return new Date(refUtc);
  }

  convertSlot(
    dayOfWeek: number,
    startTime: string,
    endTime: string,
    fromTimezone: string,
    toTimezone: string,
  ): { dayOfWeek: number; startTime: string; endTime: string } {
    const refDate = this.getReferenceDateInTz(dayOfWeek, fromTimezone);
    const [sH, sM] = startTime.split(':').map(Number);
    const [eH, eM] = endTime.split(':').map(Number);

    const startUtc = Date.UTC(
      refDate.getUTCFullYear(),
      refDate.getUTCMonth(),
      refDate.getUTCDate(),
      sH,
      sM,
    );
    const endUtc = Date.UTC(
      refDate.getUTCFullYear(),
      refDate.getUTCMonth(),
      refDate.getUTCDate(),
      eH,
      eM,
    );

    const fmt = new Intl.DateTimeFormat('en-CA', {
      timeZone: toTimezone,
      weekday: 'long',
      hour: '2-digit',
      minute: '2-digit',
      hour12: false,
    });

    const dayMap: Record<string, number> = {
      sunday: 0,
      monday: 1,
      tuesday: 2,
      wednesday: 3,
      thursday: 4,
      friday: 5,
      saturday: 6,
    };

    const startStr = fmt.format(new Date(startUtc));
    const endStr = fmt.format(new Date(endUtc));

    const startParts = startStr.split(', ');
    const endParts = endStr.split(', ');

    return {
      dayOfWeek: dayMap[startParts[0]?.toLowerCase()] ?? dayOfWeek,
      startTime: startParts[1] || startTime,
      endTime: endParts[1] || endTime,
    };
  }
}

import {
  ExceptionFilter,
  Catch,
  ArgumentsHost,
  HttpException,
  HttpStatus,
} from '@nestjs/common';
import { Request, Response } from 'express';

@Catch()
export class AllExceptionsFilter implements ExceptionFilter {
  catch(exception: unknown, host: ArgumentsHost) {
    const ctx = host.switchToHttp();
    const response = ctx.getResponse<Response>();
    const request = ctx.getRequest<Request>();

    const status =
      exception instanceof HttpException
        ? exception.getStatus()
        : HttpStatus.INTERNAL_SERVER_ERROR;

    const exceptionResponse =
      exception instanceof HttpException
        ? exception.getResponse()
        : 'Internal server error';

    const message =
      typeof exceptionResponse === 'string'
        ? exceptionResponse
        : ((exceptionResponse as any).message ?? exceptionResponse);

    response.status(status).json({
      statusCode: status,
      message,
      error:
        exception instanceof HttpException
          ? exception.name
          : 'InternalServerError',
      timestamp: new Date().toISOString(),
      path: request.url,
    });
  }
}

import { Injectable, NestMiddleware } from '@nestjs/common';
import type { Request, Response, NextFunction } from 'express';

const UNSAFE_PATTERN = /[<>]/g;

function sanitizeValue(value: unknown): unknown {
  if (typeof value === 'string') {
    return value.replace(UNSAFE_PATTERN, '').trim();
  }
  if (Array.isArray(value)) {
    return value.map(sanitizeValue);
  }
  if (value && typeof value === 'object') {
    const sanitized: Record<string, unknown> = {};
    for (const [k, v] of Object.entries(value as Record<string, unknown>)) {
      sanitized[k] = sanitizeValue(v);
    }
    return sanitized;
  }
  return value;
}

@Injectable()
export class XssCleanMiddleware implements NestMiddleware {
  use(req: Request, _res: Response, next: NextFunction) {
    if (req.body && typeof req.body === 'object') {
      req.body = sanitizeValue(req.body) as typeof req.body;
    }
    next();
  }
}

import {
  WebSocketGateway,
  SubscribeMessage,
  WebSocketServer,
  OnGatewayConnection,
  OnGatewayDisconnect,
} from '@nestjs/websockets';
import {
  Injectable,
  BadRequestException,
  OnApplicationShutdown,
} from '@nestjs/common';
import { Server, Socket } from 'socket.io';
import { JwtService } from '@nestjs/jwt';
import { ConfigService } from '@nestjs/config';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { LessonStatus } from '@mrh/types';
import { Lesson } from '../entities/lesson.entity.js';
import { Classroom } from '../entities/classroom.entity.js';
import { RedisService } from '../redis/redis.service.js';

interface ConnectedClient {
  socketId: string;
  userId: string;
  role: string;
}

interface HealthRecord {
  userId: string;
  socketId: string;
  rtt: number;
  lastSeen: number;
}

@Injectable()
@WebSocketGateway({
  namespace: '/classroom',
  cors: {
    origin: process.env.FRONTEND_URL || 'http://localhost:3000',
    credentials: true,
  },
})
export class ClassroomGateway
  implements OnGatewayConnection, OnGatewayDisconnect, OnApplicationShutdown
{
  private static readonly MAX_ACTIONS_PER_PAGE = 2000;
  private static readonly MAX_CHAT_PER_MINUTE = 30;
  @WebSocketServer()
  server: Server;

  private connectedClients = new Map<string, ConnectedClient[]>();
  private healthRecords = new Map<string, HealthRecord>();
  private healthInterval: ReturnType<typeof setInterval> | null = null;
  private chatRateLimits = new Map<
    string,
    { count: number; resetAt: number }
  >();

  constructor(
    private readonly jwtService: JwtService,
    private readonly configService: ConfigService,
    private readonly redisService: RedisService,
    @InjectRepository(Lesson)
    private readonly lessonRepository: Repository<Lesson>,
    @InjectRepository(Classroom)
    private readonly classroomRepository: Repository<Classroom>,
  ) {}

  async handleConnection(socket: Socket) {
    try {
      const token =
        socket.handshake.auth?.token ||
        socket.handshake.headers?.authorization?.replace('Bearer ', '');

      if (!token) {
        socket.disconnect(true);
        return;
      }

      const payload = await this.jwtService.verifyAsync(token);
      const { sub: userId, role } = payload;

      const existing = this.connectedClients.get(userId) || [];
      existing.push({ socketId: socket.id, userId, role });
      this.connectedClients.set(userId, existing);

      socket.data.userId = userId;
      socket.data.role = role;
      this.ensureHealthInterval();
    } catch {
      socket.disconnect(true);
    }
  }

  handleDisconnect(socket: Socket) {
    const userId = socket.data.userId;
    if (!userId) return;

    const clients = this.connectedClients.get(userId) || [];
    const filtered = clients.filter((c) => c.socketId !== socket.id);
    if (filtered.length === 0) {
      this.connectedClients.delete(userId);
    } else {
      this.connectedClients.set(userId, filtered);
    }
  }

  @SubscribeMessage('join_lesson')
  async handleJoinLesson(socket: Socket, payload: { lessonId: string }) {
    const { lessonId } = payload;

    const lesson = await this.lessonRepository.findOne({
      where: { id: lessonId },
      select: { id: true, studentId: true, tutorId: true, status: true },
    });
    if (!lesson) {
      socket.emit('error_message', 'Lesson not found');
      return;
    }
    if (
      lesson.status === LessonStatus.COMPLETED ||
      lesson.status === LessonStatus.CANCELLED
    ) {
      socket.emit('error_message', 'This lesson is no longer available');
      return;
    }
    const classroom = await this.classroomRepository.findOne({
      where: { lessonId },
    });
    if (classroom && !classroom.isActive) {
      socket.emit('error_message', 'Classroom is closed');
      return;
    }
    if (
      lesson.studentId !== socket.data.userId &&
      lesson.tutorId !== socket.data.userId &&
      socket.data.role !== 'admin'
    ) {
      socket.emit('error_message', 'You are not a participant of this lesson');
      return;
    }

    socket.join(lessonId);

    socket.data.currentLesson = lessonId;

    const whiteboardKey = `whiteboard:${lessonId}`;
    let whiteboardState = await this.redisService.get(whiteboardKey);
    if (!whiteboardState) {
      whiteboardState = JSON.stringify({ pages: { '1': [] }, currentPage: 1 });
      await this.redisService.set(whiteboardKey, whiteboardState, 'EX', 86400);
    }

    socket.emit('whiteboard_sync', JSON.parse(whiteboardState));

    socket.to(lessonId).emit('peer_joined', {
      userId: socket.data.userId,
      role: socket.data.role,
    });
  }

  onApplicationShutdown() {
    if (this.healthInterval) {
      clearInterval(this.healthInterval);
      this.healthInterval = null;
    }
  }

  private assertLessonMembership(socket: Socket, lessonId: string): boolean {
    return socket.data.currentLesson === lessonId;
  }

  private checkChatRateLimit(socketId: string): boolean {
    const now = Date.now();
    const record = this.chatRateLimits.get(socketId);
    if (!record || now > record.resetAt) {
      this.chatRateLimits.set(socketId, { count: 1, resetAt: now + 60000 });
      return true;
    }
    if (record.count >= ClassroomGateway.MAX_CHAT_PER_MINUTE) return false;
    record.count++;
    return true;
  }

  @SubscribeMessage('send_chat')
  handleSendChat(
    socket: Socket,
    payload: { lessonId: string; content: string },
  ) {
    const { lessonId, content } = payload;
    if (!this.assertLessonMembership(socket, lessonId)) return;
    if (!this.checkChatRateLimit(socket.id)) return;
    if (!content || typeof content !== 'string') return;
    if (content.length > 2000) return;

    const sanitized = content
      .replace(/<[^>]*>/g, '')
      .replace(/[<>]/g, '')
      .trim();
    if (!sanitized) return;

    this.server.to(lessonId).emit('chat_message', {
      senderId: socket.data.userId,
      content: sanitized,
      timestamp: new Date().toISOString(),
    });
  }

  @SubscribeMessage('canvas_draw')
  async handleCanvasDraw(
    socket: Socket,
    payload: { lessonId: string; page: number; data: unknown },
  ) {
    const { lessonId, page, data } = payload;
    if (!this.assertLessonMembership(socket, lessonId)) return;
    socket.to(lessonId).emit('canvas_update', {
      userId: socket.data.userId,
      page,
      data,
    });

    const whiteboardKey = `whiteboard:${lessonId}`;
    const existing = await this.redisService.get(whiteboardKey);
    if (existing) {
      try {
        const parsed = JSON.parse(existing);
        const pageStr = String(page);
        if (!parsed.pages[pageStr]) {
          parsed.pages[pageStr] = [];
        }
        if (
          parsed.pages[pageStr].length < ClassroomGateway.MAX_ACTIONS_PER_PAGE
        ) {
          parsed.pages[pageStr].push(data);
        }
        await this.redisService.set(
          whiteboardKey,
          JSON.stringify(parsed),
          'EX',
          86400,
        );
      } catch {
        // ignore parse errors
      }
    }
  }

  @SubscribeMessage('whiteboard_sync')
  async handleWhiteboardSync(socket: Socket, payload: { lessonId: string }) {
    const { lessonId } = payload;
    if (!this.assertLessonMembership(socket, lessonId)) return;
    const whiteboardKey = `whiteboard:${lessonId}`;
    const state = await this.redisService.get(whiteboardKey);
    if (state) {
      socket.emit('whiteboard_sync', JSON.parse(state));
    }
  }

  @SubscribeMessage('whiteboard_page_change')
  async handleWhiteboardPageChange(
    socket: Socket,
    payload: { lessonId: string; page: number },
  ) {
    const { lessonId, page } = payload;
    if (!this.assertLessonMembership(socket, lessonId)) return;
    const whiteboardKey = `whiteboard:${lessonId}`;
    const existing = await this.redisService.get(whiteboardKey);
    if (existing) {
      try {
        const parsed = JSON.parse(existing);
        parsed.currentPage = page;
        await this.redisService.set(
          whiteboardKey,
          JSON.stringify(parsed),
          'EX',
          86400,
        );
      } catch {
        // ignore
      }
    }

    socket.to(lessonId).emit('whiteboard_page_change', { page });
  }

  private isInSameLesson(userId1: string, userId2: string): boolean {
    const clients1 = this.connectedClients.get(userId1);
    const clients2 = this.connectedClients.get(userId2);
    if (!clients1 || !clients2) return false;

    for (const c1 of clients1) {
      const socket1 = this.server.sockets.sockets.get(c1.socketId);
      if (!socket1) continue;
      for (const c2 of clients2) {
        const socket2 = this.server.sockets.sockets.get(c2.socketId);
        if (!socket2) continue;
        for (const room1 of socket1.rooms) {
          if (room1 === socket1.id) continue;
          for (const room2 of socket2.rooms) {
            if (room2 === socket2.id) continue;
            if (room1 === room2) return true;
          }
        }
      }
    }
    return false;
  }

  @SubscribeMessage('webrtc_offer')
  handleWebrtcOffer(
    socket: Socket,
    payload: { lessonId: string; targetUserId: string; offer: unknown },
  ) {
    const { lessonId, targetUserId, offer } = payload;
    if (socket.data.currentLesson !== lessonId) return;
    if (!this.isInSameLesson(socket.data.userId, targetUserId)) return;
    const targetClients = this.connectedClients.get(targetUserId);
    if (targetClients) {
      for (const client of targetClients) {
        this.server.to(client.socketId).emit('webrtc_offer', {
          userId: socket.data.userId,
          offer,
        });
      }
    }
  }

  @SubscribeMessage('webrtc_answer')
  handleWebrtcAnswer(
    socket: Socket,
    payload: { lessonId: string; targetUserId: string; answer: unknown },
  ) {
    const { lessonId, targetUserId, answer } = payload;
    if (socket.data.currentLesson !== lessonId) return;
    if (!this.isInSameLesson(socket.data.userId, targetUserId)) return;
    const targetClients = this.connectedClients.get(targetUserId);
    if (targetClients) {
      for (const client of targetClients) {
        this.server.to(client.socketId).emit('webrtc_answer', {
          userId: socket.data.userId,
          answer,
        });
      }
    }
  }

  @SubscribeMessage('webrtc_ice_candidate')
  handleWebrtcIceCandidate(
    socket: Socket,
    payload: { lessonId: string; targetUserId: string; candidate: unknown },
  ) {
    const { lessonId, targetUserId, candidate } = payload;
    if (socket.data.currentLesson !== lessonId) return;
    if (!this.isInSameLesson(socket.data.userId, targetUserId)) return;
    const targetClients = this.connectedClients.get(targetUserId);
    if (targetClients) {
      for (const client of targetClients) {
        this.server.to(client.socketId).emit('webrtc_ice_candidate', {
          userId: socket.data.userId,
          candidate,
        });
      }
    }
  }

  @SubscribeMessage('webrtc_end')
  handleWebrtcEnd(socket: Socket, payload: { lessonId: string }) {
    const { lessonId } = payload;
    if (!this.assertLessonMembership(socket, lessonId)) return;
    socket.to(lessonId).emit('webrtc_end', {
      userId: socket.data.userId,
    });
  }

  @SubscribeMessage('camera_offer')
  handleCameraOffer(
    socket: Socket,
    payload: { lessonId: string; targetUserId: string; offer: unknown },
  ) {
    const { lessonId, targetUserId, offer } = payload;
    if (socket.data.currentLesson !== lessonId) return;
    if (!this.isInSameLesson(socket.data.userId, targetUserId)) return;
    const targetClients = this.connectedClients.get(targetUserId);
    if (targetClients) {
      for (const client of targetClients) {
        this.server.to(client.socketId).emit('camera_offer', {
          userId: socket.data.userId,
          offer,
        });
      }
    }
  }

  @SubscribeMessage('camera_answer')
  handleCameraAnswer(
    socket: Socket,
    payload: { lessonId: string; targetUserId: string; answer: unknown },
  ) {
    const { lessonId, targetUserId, answer } = payload;
    if (socket.data.currentLesson !== lessonId) return;
    if (!this.isInSameLesson(socket.data.userId, targetUserId)) return;
    const targetClients = this.connectedClients.get(targetUserId);
    if (targetClients) {
      for (const client of targetClients) {
        this.server.to(client.socketId).emit('camera_answer', {
          userId: socket.data.userId,
          answer,
        });
      }
    }
  }

  @SubscribeMessage('camera_ice_candidate')
  handleCameraIceCandidate(
    socket: Socket,
    payload: { lessonId: string; targetUserId: string; candidate: unknown },
  ) {
    const { lessonId, targetUserId, candidate } = payload;
    if (socket.data.currentLesson !== lessonId) return;
    if (!this.isInSameLesson(socket.data.userId, targetUserId)) return;
    const targetClients = this.connectedClients.get(targetUserId);
    if (targetClients) {
      for (const client of targetClients) {
        this.server.to(client.socketId).emit('camera_ice_candidate', {
          userId: socket.data.userId,
          candidate,
        });
      }
    }
  }

  @SubscribeMessage('camera_ready')
  handleCameraReady(socket: Socket, payload: { lessonId: string }) {
    const { lessonId } = payload;
    if (!this.assertLessonMembership(socket, lessonId)) return;
    socket.to(lessonId).emit('camera_ready', {
      userId: socket.data.userId,
    });
  }

  @SubscribeMessage('ping_health')
  handlePingHealth(socket: Socket, payload: { timestamp: number }) {
    socket.emit('pong_health', {
      timestamp: payload.timestamp,
      serverTime: Date.now(),
    });
  }

  @SubscribeMessage('health_report')
  handleHealthReport(
    socket: Socket,
    payload: { lessonId: string; rtt: number },
  ) {
    const { lessonId, rtt } = payload;
    if (!this.assertLessonMembership(socket, lessonId)) return;
    const userId = socket.data.userId;
    if (!userId || !lessonId) return;

    this.healthRecords.set(socket.id, {
      userId,
      socketId: socket.id,
      rtt,
      lastSeen: Date.now(),
    });

    const roomHealth = Array.from(this.healthRecords.values())
      .filter((r) => {
        const sock = this.server.sockets.sockets.get(r.socketId);
        return sock && sock.rooms.has(lessonId);
      })
      .map((r) => ({ userId: r.userId, rtt: r.rtt }));

    this.server
      .to(lessonId)
      .emit('connection_health', { participants: roomHealth });
  }

  private ensureHealthInterval() {
    if (this.healthInterval) return;
    this.healthInterval = setInterval(() => {
      const now = Date.now();
      for (const [socketId, record] of this.healthRecords) {
        if (now - record.lastSeen > 15000) {
          this.healthRecords.delete(socketId);
        }
      }
    }, 10000);
  }

  @SubscribeMessage('leave_lesson')
  handleLeaveLesson(socket: Socket, payload: { lessonId: string }) {
    const { lessonId } = payload;
    if (!this.assertLessonMembership(socket, lessonId)) return;
    this.healthRecords.delete(socket.id);
    socket.to(lessonId).emit('peer_left', {
      userId: socket.data.userId,
    });
    socket.leave(lessonId);
    socket.data.currentLesson = null;
  }
}

