import {
  BadRequestException,
  Injectable,
  NotFoundException,
} from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { InjectDataSource, InjectRepository } from '@nestjs/typeorm';
import { v2 as cloudinary, type UploadApiResponse } from 'cloudinary';
import { DataSource, Repository, type DeepPartial } from 'typeorm';
import { PaymentMethod, PaymentStatus } from '@mrh/types';
import { Payment } from '../entities/payment.entity.js';
import { StudentProfile } from '../entities/student-profile.entity.js';
import { User } from '../entities/user.entity.js';
import { SubmitPaymentDto } from './dto/submit-payment.dto.js';
import { StripeService } from './stripe/stripe.service.js';
import { EmailService } from '../services/email.service.js';
import { CommissionService } from '../services/commission.service.js';

@Injectable()
export class PaymentsService {
  constructor(
    @InjectRepository(Payment)
    private readonly paymentRepository: Repository<Payment>,
    @InjectRepository(StudentProfile)
    private readonly studentProfileRepository: Repository<StudentProfile>,
    @InjectRepository(User)
    private readonly userRepository: Repository<User>,
    @InjectDataSource()
    private readonly dataSource: DataSource,
    private readonly configService: ConfigService,
    private readonly stripeService: StripeService,
    private readonly emailService: EmailService,
    private readonly commissionService: CommissionService,
  ) {
    cloudinary.config({
      cloud_name: this.configService.get<string>('CLOUDINARY_CLOUD_NAME'),
      api_key: this.configService.get<string>('CLOUDINARY_API_KEY'),
      api_secret: this.configService.get<string>('CLOUDINARY_API_SECRET'),
    });
  }

  async submitPayment(
    userId: string,
    dto: SubmitPaymentDto,
    screenshotFile?: Express.Multer.File,
  ) {
    const user = await this.userRepository.findOne({ where: { id: userId } });
    if (!user) {
      throw new NotFoundException('User not found');
    }

    if (dto.idempotencyKey) {
      const existing = await this.paymentRepository.findOne({
        where: { idempotencyKey: dto.idempotencyKey },
      });
      if (existing) {
        throw new BadRequestException(
          'This payment has already been submitted',
        );
      }
    }

    const isCardPayment = dto.method === PaymentMethod.CARD;
    if (isCardPayment && !this.stripeService.isConfigured()) {
      throw new BadRequestException('Stripe payments are not configured');
    }

    let receiptUrl: string | null = null;
    if (screenshotFile) {
      receiptUrl = await this.uploadToCloudinary(screenshotFile.buffer);
    }

    const receiptRequiredMethods: PaymentMethod[] = [
      PaymentMethod.VODAFONE,
      PaymentMethod.INSTAPAY,
      PaymentMethod.BINANCE,
      PaymentMethod.BANK,
    ];
    if (receiptRequiredMethods.includes(dto.method) && !screenshotFile) {
      throw new BadRequestException(
        'A receipt screenshot is required for this payment method',
      );
    }

    const payment = this.paymentRepository.create({
      userId,
      amount: dto.amount,
      method: dto.method,
      status: PaymentStatus.PENDING,
      receiptUrl,
      adminNote: dto.adminNote ?? null,
      idempotencyKey: dto.idempotencyKey ?? null,
    } as unknown as DeepPartial<Payment>);

    await this.paymentRepository.save(payment);

    let checkoutUrl = undefined;
    if (dto.method === PaymentMethod.CARD) {
      const session = await this.stripeService.createCheckoutSession(
        userId,
        dto.amount,
        payment.id,
      );
      checkoutUrl = session.url;
    }

    return { payment, checkoutUrl };
  }

  async getPaymentHistory(userId: string) {
    return this.paymentRepository.find({
      where: { userId },
      order: { createdAt: 'DESC' },
    });
  }

  async getAllPayments() {
    return this.paymentRepository.find({
      relations: { user: true },
      order: { createdAt: 'DESC' },
    });
  }

  async approvePayment(paymentId: string, adminId: string) {
    return this.dataSource
      .transaction(async (manager) => {
        const payment = await manager.findOne(Payment, {
          where: { id: paymentId },
          lock: { mode: 'pessimistic_write' },
        });

        if (!payment) {
          throw new NotFoundException('Payment not found');
        }

        if (payment.status !== PaymentStatus.PENDING) {
          throw new BadRequestException('Payment is already processed');
        }

        payment.status = PaymentStatus.APPROVED;
        payment.adminNote = `Approved by admin ${adminId}`;
        await manager.save(Payment, payment);

        const balanceToAdd = await this.commissionService.amountToCredits(
          payment.amount,
        );
        await manager.increment(
          StudentProfile,
          { userId: payment.userId },
          'balance',
          balanceToAdd,
        );

        return { payment, balanceToAdd };
      })
      .then(async ({ payment, balanceToAdd }) => {
        const user = await this.userRepository.findOne({
          where: { id: payment.userId },
        });
        if (user?.email) {
          this.emailService
            .sendEmail(
              user.email,
              'Payment Approved ظ¤ MRH Academy',
              `<p>Your payment has been approved.</p>
<p>Amount: $${payment.amount.toFixed(2)}</p>
<p>Method: ${payment.method}</p>
<p>Credits Added: ${balanceToAdd.toFixed(2)}</p>`,
            )
            .catch(() => {});
        }
        return payment;
      });
  }

  async rejectPayment(paymentId: string, adminId: string, reason?: string) {
    return this.dataSource.transaction(async (manager) => {
      const payment = await manager.findOne(Payment, {
        where: { id: paymentId },
        lock: { mode: 'pessimistic_write' },
      });

      if (!payment) {
        throw new NotFoundException('Payment not found');
      }

      if (payment.status !== PaymentStatus.PENDING) {
        throw new BadRequestException('Payment is already processed');
      }

      payment.status = PaymentStatus.REJECTED;
      payment.adminNote = reason ?? `Rejected by admin ${adminId}`;
      await manager.save(Payment, payment);

      return payment;
    });
  }

  private uploadToCloudinary(buffer: Buffer): Promise<string> {
    return new Promise((resolve, reject) => {
      const stream = cloudinary.uploader.upload_stream(
        { folder: 'mrh-academy/payments' },
        (error, result) => {
          if (error || !result) {
            reject(
              error instanceof Error
                ? error
                : new Error('Cloudinary upload failed'),
            );
            return;
          }
          resolve(result.secure_url);
        },
      );
      stream.end(buffer);
    });
  }
}

import { Injectable, RawBodyRequest } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import Stripe from 'stripe';
import { Request } from 'express';

@Injectable()
export class StripeService {
  private stripe: Stripe;
  private readonly secret?: string;

  constructor(private readonly configService: ConfigService) {
    this.secret = this.configService.get<string>('STRIPE_SECRET_KEY');
    this.stripe = new Stripe(this.secret || 'sk_test_placeholder', {
      apiVersion: '2025-01-27.acacia' as any,
    });
  }

  isConfigured() {
    return Boolean(this.secret);
  }

  async createCheckoutSession(
    userId: string,
    amount: number,
    paymentId: string,
  ) {
    const frontendUrl =
      this.configService.get<string>('FRONTEND_URL') || 'http://localhost:3000';

    // Convert USD to cents
    const amountInCents = Math.round(amount * 100);

    const session = await this.stripe.checkout.sessions.create({
      payment_method_types: ['card'],
      line_items: [
        {
          price_data: {
            currency: 'usd',
            product_data: {
              name: 'Mr.H Academy Balance',
              description: `Add $${amount} to your student balance`,
            },
            unit_amount: amountInCents,
          },
          quantity: 1,
        },
      ],
      mode: 'payment',
      success_url: `${frontendUrl}/student?payment_success=true&session_id={CHECKOUT_SESSION_ID}`,
      cancel_url: `${frontendUrl}/student?payment_cancelled=true`,
      client_reference_id: paymentId,
      metadata: {
        userId,
        paymentId,
      },
    });

    return session;
  }

  // ظ¤ظ¤ظ¤ Stripe Connect ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤ظ¤

  async createConnectedAccount(tutorEmail: string): Promise<Stripe.Account> {
    return this.stripe.accounts.create({
      type: 'express',
      email: tutorEmail,
      capabilities: {
        transfers: { requested: true },
      },
      business_type: 'individual',
    });
  }

  async generateOnboardingLink(accountId: string): Promise<string> {
    const frontendUrl =
      this.configService.get<string>('FRONTEND_URL') || 'http://localhost:3000';
    const link = await this.stripe.accountLinks.create({
      account: accountId,
      refresh_url: `${frontendUrl}/tutor?connect_refresh=true`,
      return_url: `${frontendUrl}/tutor?connect_success=true`,
      type: 'account_onboarding',
    });
    return link.url;
  }

  async retrieveAccount(accountId: string): Promise<Stripe.Account> {
    return this.stripe.accounts.retrieve(accountId);
  }

  async createPayout(
    accountId: string,
    amountCents: number,
    idempotencyKey?: string,
  ): Promise<Stripe.Transfer> {
    return this.stripe.transfers.create(
      {
        amount: amountCents,
        currency: 'usd',
        destination: accountId,
      },
      idempotencyKey ? { idempotencyKey } : undefined,
    );
  }

  constructEvent(req: RawBodyRequest<Request>) {
    const signature = req.headers['stripe-signature'];
    const webhookSecret = this.configService.get<string>(
      'STRIPE_WEBHOOK_SECRET',
    );

    if (!signature || !webhookSecret) {
      throw new Error('Missing stripe signature or webhook secret');
    }

    if (!req.rawBody) {
      throw new Error('Missing raw body');
    }

    return this.stripe.webhooks.constructEvent(
      req.rawBody,
      signature,
      webhookSecret,
    );
  }
}

import { Injectable, OnModuleDestroy, OnModuleInit } from '@nestjs/common';
import { Logger } from '@nestjs/common';
import Redis from 'ioredis';

@Injectable()
export class RedisService implements OnModuleInit, OnModuleDestroy {
  private readonly logger = new Logger(RedisService.name);
  public readonly redis: Redis;
  public connected = false;

  constructor() {
    this.redis = new Redis(process.env.REDIS_URL!, {
      lazyConnect: true,
      maxRetriesPerRequest: 0,
      retryStrategy: () => null,
    });
    this.redis.on('error', () => {});
  }

  async onModuleInit() {
    try {
      await this.redis.connect();
      await this.redis.ping();
      this.connected = true;
      this.logger.log('Redis connected');
    } catch {
      this.logger.warn('Redis unavailable ظ¤ session enforcement disabled');
    }
  }

  async set(key: string, value: string, mode: 'EX', ttl: number) {
    if (!this.connected) return;
    await this.redis.set(key, value, mode, ttl);
  }

  async get(key: string) {
    if (!this.connected) return null;
    return this.redis.get(key);
  }

  async del(key: string) {
    if (!this.connected) return;
    await this.redis.del(key);
  }

  async delPattern(pattern: string) {
    if (!this.connected) return;
    const keys: string[] = [];
    let cursor = '0';
    do {
      const result = await this.redis.scan(
        cursor,
        'MATCH',
        pattern,
        'COUNT',
        100,
      );
      cursor = result[0];
      keys.push(...result[1]);
    } while (cursor !== '0');
    if (keys.length > 0) {
      await this.redis.del(...keys);
    }
  }

  async getOrSet<T>(
    key: string,
    factory: () => Promise<T>,
    ttlSeconds: number = 300, // 5 mins default
  ): Promise<T> {
    if (!this.connected) {
      return factory();
    }
    const cached = await this.get(key);
    if (cached) {
      try {
        return JSON.parse(cached);
      } catch {
        // ignore
      }
    }
    const value = await factory();
    await this.set(key, JSON.stringify(value), 'EX', ttlSeconds);
    return value;
  }

  onModuleDestroy() {
    this.redis.disconnect();
  }
}

