    private readonly reviewRepository: Repository<Review>,
  ) {}

  @Get('balance')
  getBalance(@CurrentUser() user: AuthenticatedUser) {
    return this.studentsService.getBalance(user.id);
  }

  @Put('profile')
  updateProfile(
    @CurrentUser() user: AuthenticatedUser,
    @Body() dto: UpdateProfileDto,
  ) {
    return this.usersService.updateProfile(user.id, dto);
  }

  @Get('payment-history')
  getPaymentHistory(@CurrentUser() user: AuthenticatedUser) {
    return this.studentsService.getPaymentHistory(user.id);
  }

  @Get('payment-methods')
  getPaymentMethods(@CurrentUser() user: AuthenticatedUser) {
    return this.studentsService.getPaymentMethods(user.id);
  }

  @Get('combined-history')
  getCombinedHistory(@CurrentUser() user: AuthenticatedUser) {
    return this.studentsService.getCombinedHistory(user.id);
  }

  @Get('lessons')
  async getLessons(@CurrentUser() user: AuthenticatedUser) {
    const lessons = await this.lessonRepository.find({
      where: { studentId: user.id },
      relations: { tutor: true },
      order: { scheduledTime: 'DESC' },
    });
    return lessons.map((l) => ({
      id: l.id,
      tutorName: l.tutor
        ? `${l.tutor.firstName} ${l.tutor.lastName}`
        : 'Unknown',
      subject: '',
      date: l.scheduledTime,
      duration: l.durationMinutes,
      price: l.price,
      status: l.status,
      roomId: l.meetUrl,
    }));
  }

  @Get('favorite-tutors')
  async getFavoriteTutors(@CurrentUser() user: AuthenticatedUser) {
    const lessons = await this.lessonRepository.find({
      where: { studentId: user.id },
      relations: { tutor: true },
    });
    const tutorIds = [
      ...new Set(lessons.map((l) => l.tutorId).filter(Boolean)),
    ];

    if (tutorIds.length === 0) return [];

    const tutors = await this.tutorProfileRepository.find({
      where: { userId: In(tutorIds), status: CourseStatus.APPROVED },
      relations: { user: true },
    });

    const result = await Promise.all(
      tutors.map(async (t) => {
        const avg = await this.reviewRepository
          .createQueryBuilder('review')
          .where('review.tutorId = :tutorId', { tutorId: t.userId })
          .andWhere('review.status = :status', {
            status: CourseStatus.APPROVED,
          })
          .select('AVG(review.rating)', 'avg')
          .getRawOne<{ avg: string | null }>();
        return {
          userId: t.userId,
          firstName: t.user?.firstName ?? '',
          lastName: t.user?.lastName ?? '',
          specialization: t.specialization,
          hourlyRate: t.hourlyRate,
          averageRating: avg?.avg ? parseFloat(avg.avg) || 0 : 0,
        };
      }),
    );

    return result.sort((a, b) => b.averageRating - a.averageRating);
  }
}

import {
  IsString,
  IsNotEmpty,
  IsArray,
  ArrayNotEmpty,
  IsNumber,
  IsOptional,
  IsUrl,
  MinLength,
  Min,
  Max,
} from 'class-validator';
import { Transform, Type } from 'class-transformer';

export class ApplyTutorDto {
  @IsString()
  @IsNotEmpty()
  @MinLength(50)
  bio: string;

  @IsString()
  @IsNotEmpty()
  @MinLength(2)
  specialization: string;

  @Transform(({ value }) => {
    if (Array.isArray(value)) return value.map(String);
    if (typeof value === 'string') {
      return value
        .split(',')
        .map((s) => s.trim())
        .filter(Boolean);
    }
    return value;
  })
  @IsArray()
  @ArrayNotEmpty()
  @IsString({ each: true })
  languages: string[];

  @Type(() => Number)
  @IsNumber()
  @Min(5)
  @Max(500)
  hourlyRate: number;

  @IsString()
  @IsOptional()
  @IsUrl({ require_protocol: true })
  videoUrl?: string;
}

import { Controller, Get, UseGuards } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { UserRole } from '@mrh/types';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard.js';
import { RolesGuard } from '../auth/guards/roles.guard.js';
import { Roles } from '../auth/decorators/roles.decorator.js';
import { CurrentUser } from '../auth/decorators/current-user.decorator.js';
import { Lesson } from '../entities/lesson.entity.js';
import { User } from '../entities/user.entity.js';

@Controller('tutor')
@UseGuards(JwtAuthGuard, RolesGuard)
@Roles(UserRole.TUTOR)
export class TutorDashboardController {
  constructor(
    @InjectRepository(Lesson)
    private readonly lessonRepository: Repository<Lesson>,
  ) {}

  @Get('students')
  async getStudents(@CurrentUser() user: { id: string }) {
    const lessons = await this.lessonRepository.find({
      where: { tutorId: user.id },
      relations: { student: true },
      order: { scheduledTime: 'DESC' },
    });

    const seen = new Map<string, { user: User; lessonCount: number }>();
    for (const l of lessons) {
      if (!l.student) continue;
      if (!seen.has(l.studentId)) {
        seen.set(l.studentId, { user: l.student, lessonCount: 0 });
      }
      seen.get(l.studentId)!.lessonCount++;
    }

    return Array.from(seen.values()).map(({ user, lessonCount }) => ({
      id: user.id,
      firstName: user.firstName,
      lastName: user.lastName,
      email: user.email,
      avatar: (user as any).avatar,
      lessonCount,
    }));
  }
}

import {
  BadRequestException,
  ConflictException,
  Injectable,
  NotFoundException,
  UnauthorizedException,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { v2 as cloudinary } from 'cloudinary';
import { ConfigService } from '@nestjs/config';
import * as nodemailer from 'nodemailer';
import { CourseStatus, LessonStatus, UserRole } from '@mrh/types';
import { TutorProfile } from '../entities/tutor-profile.entity.js';
import { User } from '../entities/user.entity.js';
import { Review } from '../entities/review.entity.js';
import { Lesson } from '../entities/lesson.entity.js';
import { Payment } from '../entities/payment.entity.js';
import { Report } from '../entities/report.entity.js';
import { ApplyTutorDto, UpdateTutorDto } from './dto/index.js';
import { RedisService } from '../redis/redis.service.js';

@Injectable()
export class TutorsService {
  private mailTransporter: nodemailer.Transporter;

  constructor(
    @InjectRepository(TutorProfile)
    private readonly tutorProfileRepository: Repository<TutorProfile>,
    @InjectRepository(User)
    private readonly userRepository: Repository<User>,
    @InjectRepository(Review)
    private readonly reviewRepository: Repository<Review>,
    @InjectRepository(Lesson)
    private readonly lessonRepository: Repository<Lesson>,
    @InjectRepository(Payment)
    private readonly paymentRepository: Repository<Payment>,
    @InjectRepository(Report)
    private readonly reportRepository: Repository<Report>,
    private readonly configService: ConfigService,
    private readonly redisService: RedisService,
  ) {
    cloudinary.config({
      cloud_name: this.configService.get<string>('CLOUDINARY_CLOUD_NAME'),
      api_key: this.configService.get<string>('CLOUDINARY_API_KEY'),
      api_secret: this.configService.get<string>('CLOUDINARY_API_SECRET'),
    });

    const smtpUser = this.configService.get<string>('SMTP_USER');
    const smtpPass = this.configService.get<string>('SMTP_PASS');

    if (!smtpUser || !smtpPass) {
      this.mailTransporter = nodemailer.createTransport({
        jsonTransport: true,
      });
      return;
    }

    this.mailTransporter = nodemailer.createTransport({
      host:
        this.configService.get<string>('SMTP_HOST') || 'smtp.ethereal.email',
      port: parseInt(this.configService.get<string>('SMTP_PORT') || '587', 10),
      secure: this.configService.get<string>('SMTP_SECURE') === 'true',
      auth: {
        user: smtpUser,
        pass: smtpPass,
      },
    } as nodemailer.TransportOptions);
  }

  async findAllWithFilters(filters: {
    minPrice?: number;
    maxPrice?: number;
    languages?: string;
    sort?: 'asc' | 'desc';
    search?: string;
  }) {
    const cacheKey = `tutors:filters:${JSON.stringify(filters)}`;
    return this.redisService.getOrSet(
      cacheKey,
      async () => {
        const query = this.tutorProfileRepository
          .createQueryBuilder('tutor')
          .leftJoinAndSelect('tutor.user', 'user')
          .where('tutor.status = :status', { status: CourseStatus.APPROVED });

        if (filters.minPrice !== undefined) {
          query.andWhere('tutor.hourlyRate >= :minPrice', {
            minPrice: filters.minPrice,
          });
        }
        if (filters.maxPrice !== undefined) {
          query.andWhere('tutor.hourlyRate <= :maxPrice', {
            maxPrice: filters.maxPrice,
          });
        }
        if (filters.languages) {
          const langs = filters.languages.split(',').map((l) => l.trim());
          query.andWhere('tutor.languages && :languages', { languages: langs });
        }
        if (filters.search) {
          query.andWhere(
            '(user.firstName ILIKE :search OR user.lastName ILIKE :search OR tutor.bio ILIKE :search OR tutor.specialization ILIKE :search)',
            { search: `%${filters.search}%` },
          );
        }

        query.orderBy(
          'tutor.hourlyRate',
          filters.sort === 'desc' ? 'DESC' : 'ASC',
        );

        return query.getMany();
      },
      60,
    ); // 1 min cache
  }

  async findTopRated(limit = 3) {
    const cacheKey = `tutors:top-rated:${limit}`;
    return this.redisService.getOrSet(
      cacheKey,
      async () => {
        const [tutors, ratings] = await Promise.all([
          this.tutorProfileRepository
            .createQueryBuilder('tutor')
            .leftJoinAndSelect('tutor.user', 'user')
            .where('tutor.status = :status', { status: CourseStatus.APPROVED })
            .getMany(),
          this.reviewRepository
            .createQueryBuilder('review')
            .select('review.tutorId', 'tutorId')
            .addSelect('AVG(review.rating)', 'avg')
            .where('review.status = :status', { status: CourseStatus.APPROVED })
            .groupBy('review.tutorId')
            .getRawMany(),
        ]);

        const ratingMap = new Map(
          ratings.map((r) => [r.tutorId, parseFloat(r.avg) || 0]),
        );

        return tutors
          .map((tutor) => ({
            ...tutor,
            averageRating: ratingMap.get(tutor.userId) ?? 0,
          }))
          .sort((a, b) => b.averageRating - a.averageRating)
          .slice(0, limit);
      },
      300,
    ); // 5 mins
  }

  async findPublicProfile(userId: string) {
    const cacheKey = `tutors:public-profile:${userId}`;
    return this.redisService.getOrSet(
      cacheKey,
      async () => {
        const tutor = await this.tutorProfileRepository.findOne({
          where: { userId, status: CourseStatus.APPROVED },
          relations: { user: true },
        });
        if (!tutor) throw new NotFoundException('Tutor profile not found');

        const avg = await this.reviewRepository
          .createQueryBuilder('review')
          .where('review.tutorId = :tutorId', { tutorId: userId })
          .andWhere('review.status = :status', {
            status: CourseStatus.APPROVED,
          })
          .select('AVG(review.rating)', 'avg')
          .getRawOne<{ avg: string | null }>();

        const reviewCount = await this.reviewRepository.count({
          where: { tutorId: userId, status: CourseStatus.APPROVED },
        });

        const { user } = tutor;
        return {
          ...tutor,
          user: {
            firstName: user.firstName,
            lastName: user.lastName,
            avatarUrl: user.avatarUrl,
          },
          averageRating: avg?.avg ? parseFloat(avg.avg) || 0 : 0,
          reviewCount,
        };
      },
      300,
    ); // 5 mins
  }

  async applyToBeTutor(
    userId: string,
    dto: ApplyTutorDto,
    documentFile?: Express.Multer.File,
  ) {
    const user = await this.userRepository.findOne({
      where: { id: userId },
      relations: { tutorProfile: true },
    });
    if (!user) throw new UnauthorizedException('User not found');

    if (user.tutorProfile) {
      throw new ConflictException('You have already applied to be a tutor');
    }

    if (user.role !== UserRole.STUDENT) {
      throw new BadRequestException('Only students can apply to become tutors');
    }

    let documentUrl: string | undefined;
    if (documentFile) {
      const allowedMimes = [
        'application/pdf',
        'application/msword',
        'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
      ];
      if (!allowedMimes.includes(documentFile.mimetype)) {
        throw new BadRequestException('Document must be a PDF or Word file');
      }
      documentUrl = await this.uploadDocumentToCloudinary(documentFile.buffer);
    }

    const tutorProfile = this.tutorProfileRepository.create({
      userId,
      bio: dto.bio,
      specialization: dto.specialization,
      languages: dto.languages,
      hourlyRate: dto.hourlyRate,
      videoUrl: dto.videoUrl,
      documentUrl,
      status: CourseStatus.PENDING,
      balance: 0,
      totalHoursTaught: 0,
    });

    const savedProfile = await this.tutorProfileRepository.save(tutorProfile);

    await this.sendEmail(
      user.email,
      'Tutor Application Received ظ¤ MRH Academy',
      `Dear ${user.firstName},\n\nThank you for applying to become a tutor at MRH Academy. Your application has been received and is currently pending review by our moderation team.\n\nSpecialization: ${dto.specialization}\nLanguages: ${dto.languages.join(', ')}\nHourly Rate: $${dto.hourlyRate.toFixed(2)}\n\nWe will review your application within 2-3 business days and notify you of the outcome via email.\n\nBest regards,\nMRH Academy Team`,
    );

    return savedProfile;
  }

  async uploadDocumentToCloudinary(buffer: Buffer): Promise<string> {
    return new Promise((resolve, reject) => {
      const stream = cloudinary.uploader.upload_stream(
        { folder: 'mrh-academy/tutor-documents', resource_type: 'raw' },
        (error, result) => {
          if (error || !result) {
            reject(new Error('Cloudinary upload failed'));
            return;
          }
          resolve(result.secure_url);
        },
      );
      stream.end(buffer);
    });
  }

  async findAllPending() {
    return this.tutorProfileRepository.find({
      where: { status: CourseStatus.PENDING },
      relations: { user: true },
    });
  }

  async findAll() {
    return this.tutorProfileRepository.find({
      relations: { user: true },
    });
  }

  async findOneByUserId(userId: string) {
    const tutor = await this.tutorProfileRepository.findOne({
      where: { userId },
      relations: { user: true },
    });
    if (!tutor) throw new NotFoundException('Tutor profile not found');
    return tutor;
  }

  async updateTutorProfile(userId: string, dto: UpdateTutorDto) {
    const tutor = await this.tutorProfileRepository.findOne({
      where: { userId },
    });
    if (!tutor) throw new NotFoundException('Tutor profile not found');

    Object.assign(tutor, dto);
    const saved = await this.tutorProfileRepository.save(tutor);
    await this.redisService.delPattern('tutors:*');
    return saved;
  }

  async getTutorStats(userId: string): Promise<{
    completedLessons: number;
    totalHoursTaught: number;
    totalEarnings: number;
    reviewCount: number;
    averageRating: number;
    studentCount: number;
  }> {
    const cacheKey = `tutors:stats:${userId}`;
    return this.redisService.getOrSet(
      cacheKey,
      async () => {
        const profile = await this.tutorProfileRepository.findOne({
          where: { userId },
        });

        const completedLessons = await this.lessonRepository.count({
          where: { tutorId: userId, status: LessonStatus.COMPLETED },
        });

        const reviewCount = await this.reviewRepository.count({
          where: { tutorId: userId, status: CourseStatus.APPROVED },
        });

        const avg = await this.reviewRepository
          .createQueryBuilder('review')
          .where('review.tutorId = :tutorId', { tutorId: userId })
          .andWhere('review.status = :status', {
            status: CourseStatus.APPROVED,
          })
          .select('AVG(review.rating)', 'avg')
          .getRawOne<{ avg: string | null }>();

        const studentRows = await this.lessonRepository
          .createQueryBuilder('lesson')
          .select('DISTINCT lesson.studentId', 'studentId')
          .where('lesson.tutorId = :tutorId', { tutorId: userId })
          .getRawMany<{ studentId: string }>();

        return {
          completedLessons,
          totalHoursTaught: profile?.totalHoursTaught ?? 0,
          totalEarnings: profile?.balance ?? 0,
          reviewCount,
          averageRating: avg?.avg ? parseFloat(avg.avg) || 0 : 0,
          studentCount: studentRows.length,
        };
      },
      120,
    ); // 2 min cache
  }

  async getTutorStudents(tutorId: string) {
    const lessons = await this.lessonRepository.find({
      where: { tutorId },
      relations: { student: true },
    });

    const studentMap = new Map<
      string,
      { user: User; lessonCount: number; totalHours: number }
    >();

    for (const lesson of lessons) {
      if (!lesson.student) continue;
      const existing = studentMap.get(lesson.studentId);
      const hours = lesson.durationMinutes / 60;
      if (existing) {
        existing.lessonCount++;
        existing.totalHours += hours;
      } else {
        studentMap.set(lesson.studentId, {
          user: lesson.student,
          lessonCount: 1,
          totalHours: hours,
        });
      }
    }

    return Array.from(studentMap.values()).map((entry) => ({
      user: {
        id: entry.user.id,
        firstName: entry.user.firstName,
        lastName: entry.user.lastName,
        avatarUrl: entry.user.avatarUrl,
      },
      lessonCount: entry.lessonCount,
      totalHours: entry.totalHours,
    }));
  }

  async approveTutor(userId: string) {
    const tutor = await this.findOneByUserId(userId);
    if (!tutor) throw new NotFoundException('Tutor profile not found');
    if (tutor.status === CourseStatus.APPROVED) {
      throw new BadRequestException('Tutor is already approved');
    }
    if (tutor.status === CourseStatus.REJECTED) {
      throw new BadRequestException('Tutor was rejected, cannot approve');
    }

    tutor.status = CourseStatus.APPROVED;
    await this.tutorProfileRepository.save(tutor);

    const user = await this.userRepository.findOneBy({ id: userId });
    if (!user) throw new NotFoundException('User not found');

    user.role = UserRole.TUTOR;
    await this.userRepository.save(user);

    await this.redisService.delPattern('tutors:*');

    await this.sendEmail(
      user.email,
      'Congratulations! Your Tutor Application Has Been Approved',
      `Hi ${user.firstName}, great news! Your tutor application has been approved. You can now start using the tutor dashboard.`,
    );

    return tutor;
  }

  async rejectTutor(userId: string, reason: string) {
    const tutor = await this.findOneByUserId(userId);
    if (!tutor) throw new NotFoundException('Tutor profile not found');
    if (tutor.status === CourseStatus.APPROVED) {
      throw new BadRequestException('Tutor is already approved, cannot reject');
    }

    tutor.status = CourseStatus.REJECTED;
    tutor.rejectionReason = reason;
    await this.tutorProfileRepository.save(tutor);

    await this.redisService.delPattern('tutors:*');

    await this.sendEmail(
      tutor.user.email,
      'Update on Your Tutor Application',
      `Hi ${tutor.user.firstName}, unfortunately your tutor application has been rejected. Reason: ${reason}`,
    );

    return tutor;
  }

  async getAdminStats(): Promise<{
    totalUsers: number;
    totalTutors: number;
    totalStudents: number;
    pendingApplications: number;
    approvedTutors: number;
    totalEarnings: number;
    openReports: number;
    completedLessons: number;
    totalRevenue: number;
  }> {
    const cacheKey = 'admin:stats';
    return this.redisService.getOrSet(
      cacheKey,
      async () => {
        const totalUsers = await this.userRepository.count();
        const totalTutors = await this.tutorProfileRepository.count({
          where: { status: CourseStatus.APPROVED },
        });
        const studentUsers = await this.userRepository.count({
          where: { role: UserRole.STUDENT },
        });
        const pendingApplications = await this.tutorProfileRepository.count({
          where: { status: CourseStatus.PENDING },
        });
        const approvedTutors = await this.tutorProfileRepository.count({
          where: { status: CourseStatus.APPROVED },
        });

        const completedLessons = await this.lessonRepository.count({
          where: { status: LessonStatus.COMPLETED },
        });

        const totalEarnings = await this.lessonRepository
          .createQueryBuilder('lesson')
          .select('COALESCE(SUM(lesson.price), 0)', 'total')
          .where('lesson.status = :status', { status: LessonStatus.COMPLETED })
          .getRawOne<{ total: number }>()
          .then((r) => parseFloat(String(r?.total ?? '0')));

        const totalRevenue = await this.lessonRepository
          .createQueryBuilder('lesson')
          .select('COALESCE(SUM(lesson.platformFee), 0)', 'total')
          .where('lesson.status = :status', { status: LessonStatus.COMPLETED })
          .getRawOne<{ total: number }>()
          .then((r) => parseFloat(String(r?.total ?? '0')));

        const openReports = await this.reportRepository.count();

        return {
          totalUsers,
          totalTutors,
          totalStudents: studentUsers,
          pendingApplications,
          approvedTutors,
          totalEarnings,
          openReports,
          completedLessons,
          totalRevenue,
        };
      },
      60,
    ); // 1 min cache
  }

  private async sendEmail(to: string, subject: string, text: string) {
    try {
      await this.mailTransporter.sendMail({
        from:
          this.configService.get<string>('SMTP_FROM') ||
          'no-reply@mrh-academy.com',
        to,
        subject,
        text,
      });
    } catch (error) {
      console.error('Failed to send email:', error);
    }
  }
}

import {
  BadRequestException,
  ConflictException,
  Injectable,
  UnauthorizedException,
} from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { InjectDataSource, InjectRepository } from '@nestjs/typeorm';
import * as bcrypt from 'bcrypt';
import { v2 as cloudinary, type UploadApiResponse } from 'cloudinary';
import { DataSource, In, Repository } from 'typeorm';
import { LessonStatus } from '@mrh/types';
import { Lesson } from '../entities/lesson.entity.js';
import { StudentProfile } from '../entities/student-profile.entity.js';

import { User } from '../entities/user.entity.js';
import { TutorProfile } from '../entities/tutor-profile.entity.js';
import { RedisService } from '../redis/redis.service.js';
import {
  ChangeEmailDto,
  ChangePasswordDto,
  UpdateProfileDto,
} from './dto/index.js';

type AvatarFile = {
  buffer: Buffer;
  mimetype: string;
  size: number;
};

@Injectable()
export class UsersService {
  private readonly maxAvatarSize = 2 * 1024 * 1024;

  constructor(
    @InjectRepository(User)
    private readonly userRepository: Repository<User>,
    @InjectDataSource()
    private readonly dataSource: DataSource,
    private readonly configService: ConfigService,
    private readonly redisService: RedisService,
  ) {
    cloudinary.config({
      cloud_name: this.configService.get<string>('CLOUDINARY_CLOUD_NAME'),
      api_key: this.configService.get<string>('CLOUDINARY_API_KEY'),
      api_secret: this.configService.get<string>('CLOUDINARY_API_SECRET'),
    });
  }

  async getMe(userId: string) {
    const user = await this.userRepository.findOne({
      where: { id: userId },
      relations: {
        studentProfile: true,
        tutorProfile: true,
      },
    });

    if (!user) {
      throw new UnauthorizedException('User not found');
    }

    return this.sanitizeUser(user);
  }

  async updateProfile(userId: string, dto: UpdateProfileDto) {
    const user = await this.userRepository.findOne({ where: { id: userId } });
    if (!user) {
      throw new UnauthorizedException('User not found');
    }

    if (dto.firstName !== undefined) user.firstName = dto.firstName;
    if (dto.lastName !== undefined) user.lastName = dto.lastName;
    if (dto.phone !== undefined) user.phone = dto.phone;
    if (dto.timezone !== undefined) user.timezone = dto.timezone;

    const updated = await this.userRepository.save(user);
    return this.sanitizeUser(updated);
  }

  async changePassword(userId: string, dto: ChangePasswordDto) {
    const user = await this.userRepository
      .createQueryBuilder('user')
      .addSelect('user.passwordHash')
      .where('user.id = :userId', { userId })
      .getOne();

    if (!user) {
      throw new UnauthorizedException('User not found');
    }

    // Google-only accounts have no password
    if (!user.passwordHash) {
      throw new BadRequestException(
        'Password change is not available for accounts linked via Google',
      );
    }

    const isPasswordValid = await bcrypt.compare(
      dto.currentPassword,
      user.passwordHash,
    );
    if (!isPasswordValid) {
      throw new UnauthorizedException('Current password is incorrect');
    }

    user.passwordHash = await bcrypt.hash(dto.newPassword, 12);
    await this.userRepository.save(user);

    return { message: 'Password updated successfully' };
  }

  async changeEmail(userId: string, dto: ChangeEmailDto) {
    const existing = await this.userRepository.findOne({
      where: { email: dto.newEmail },
    });
    if (existing && existing.id !== userId) {
      throw new ConflictException('Email is already registered');
    }

    const user = await this.userRepository
      .createQueryBuilder('user')
      .addSelect('user.passwordHash')
      .where('user.id = :userId', { userId })
      .getOne();

    if (!user) {
      throw new UnauthorizedException('User not found');
    }

    if (user.passwordHash) {
      const isPasswordValid = await bcrypt.compare(
        dto.currentPassword,
        user.passwordHash,
      );
      if (!isPasswordValid) {
        throw new UnauthorizedException('Current password is incorrect');
      }
    }

    user.email = dto.newEmail;
    try {
      const updated = await this.userRepository.save(user);
      return this.sanitizeUser(updated);
    } catch (error: unknown) {
      if (this.isEmailConflict(error)) {
        throw new ConflictException('Email is already registered');
      }
      throw error;
    }
  }

  async updateAvatar(userId: string, file: AvatarFile | undefined) {
    if (!file) {
      throw new BadRequestException('Avatar file is required');
    }
    if (file.size > this.maxAvatarSize) {
      throw new BadRequestException('Avatar file must be 2MB or smaller');
    }

    const uploadResult = await this.uploadToCloudinary(file.buffer);

    await this.userRepository.update(userId, {
      avatarUrl: uploadResult.secure_url,
    });

    return { avatarUrl: uploadResult.secure_url };
  }

  async switchRole(userId: string) {
    const user = await this.userRepository.findOne({
      where: { id: userId },
      relations: { tutorProfile: true, studentProfile: true },
    });
    if (!user) throw new UnauthorizedException('User not found');

    if (user.role === 'student') {
      if (!user.tutorProfile) {
        throw new BadRequestException(
          'You need to apply and be approved as a tutor first',
        );
      }
      user.role = 'tutor' as any;
    } else if (user.role === 'tutor') {
      user.role = 'student' as any;
    } else {
      throw new BadRequestException('Admins cannot switch roles');
    }

    const saved = await this.userRepository.save(user);
    return this.sanitizeUser(saved);
  }

  async deleteMe(userId: string) {
    await this.dataSource.transaction(async (manager) => {
      const user = await manager.findOne(User, {
        where: { id: userId },
        lock: { mode: 'pessimistic_write' },
      });
      if (!user) {
        throw new UnauthorizedException('User not found');
      }

      const lessons = await manager.find(Lesson, {
        where: [
          {
            studentId: userId,
            status: In([LessonStatus.PENDING, LessonStatus.CONFIRMED]),
          },
          {
            tutorId: userId,
            status: In([LessonStatus.PENDING, LessonStatus.CONFIRMED]),
          },
        ],
      });

      for (const lesson of lessons) {
        await manager.increment(
          StudentProfile,
          { userId: lesson.studentId },
          'balance',
          lesson.price,
        );

        lesson.status = LessonStatus.CANCELLED;
        await manager.save(Lesson, lesson);
      }

      user.deletedAt = new Date();
      await manager.save(User, user);
    });

    // Invalidate Redis session after transaction completes
    await this.redisService.del(`user_session:${userId}`);

    return { message: 'Account deleted successfully' };
  }

  private isEmailConflict(error: unknown) {
    if (!error || typeof error !== 'object') {
      return false;
    }

    const databaseError = error as { code?: string; constraint?: string };
    return (
      databaseError.code === '23505' ||
      Boolean(databaseError.constraint?.includes('email'))
    );
  }

  private uploadToCloudinary(buffer: Buffer): Promise<UploadApiResponse> {
    return new Promise((resolve, reject) => {
      const stream = cloudinary.uploader.upload_stream(
        { folder: 'mrh-academy/avatars' },
        (error, result) => {
          if (error || !result) {
            reject(
              error instanceof Error
                ? error
                : new Error('Cloudinary upload failed'),
            );
            return;
          }
          resolve(result);
        },
      );
      stream.end(buffer);
    });
  }

  private sanitizeUser(user: User) {
    const safeUser = { ...user } as Partial<User>;
    delete safeUser.passwordHash;
    return safeUser;
  }
}

import {
  Controller,
  Get,
  Post,
  Delete,
  Body,
  Param,
  Query,
  UseGuards,
} from '@nestjs/common';
import { Throttle } from '@nestjs/throttler';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard.js';
import { CurrentUser } from '../auth/decorators/current-user.decorator.js';
import { VocabularyService } from './vocabulary.service.js';
import { DefineWordDto } from './dto/define-word.dto.js';

@Controller('vocabulary')
@UseGuards(JwtAuthGuard)
export class VocabularyController {
  constructor(private readonly vocabularyService: VocabularyService) {}

  @Post('define')
  @Throttle({ default: { limit: 10, ttl: 60000 } })
  async defineWord(
    @CurrentUser() user: { id: string },
    @Body() dto: DefineWordDto,
  ) {
    return this.vocabularyService.defineWord(dto.word, dto.language);
  }

  @Post('save')
  async saveWord(
    @CurrentUser() user: { id: string },
    @Body()
    dto: {
      word: string;
      definition: string;
      examples?: string;
      translation?: string;
      language?: string;
      contextSentence?: string;
    },
  ) {
    return this.vocabularyService.saveWord(user.id, dto);
  }

  @Get()
  async listWords(@CurrentUser() user: { id: string }) {
    return this.vocabularyService.listWords(user.id);
  }

  @Delete(':id')
  async deleteWord(
    @CurrentUser() user: { id: string },
    @Param('id') id: string,
  ) {
    return this.vocabularyService.deleteWord(user.id, id);
  }
}

import {
  Injectable,
  NotFoundException,
  ServiceUnavailableException,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { GeminiService } from '../services/gemini.service.js';
import { VocabularyWord } from '../entities/vocabulary-word.entity.js';

@Injectable()
export class VocabularyService {
  constructor(
    @InjectRepository(VocabularyWord)
    private readonly vocabRepository: Repository<VocabularyWord>,
    private readonly geminiService: GeminiService,
  ) {}

  async defineWord(word: string, language = 'en') {
    if (!this.geminiService.isConfigured()) {
      throw new ServiceUnavailableException(
        'AI vocabulary service is not configured',
      );
    }

    const prompt = `You are a vocabulary tutor. For the word/phrase "${word}" (language: ${language}), provide a JSON response with exactly these fields:
{
  "word": "${word}",
  "pronunciation": "phonetic pronunciation",
  "definition": "clear definition in English",
  "examples": ["example sentence 1", "example sentence 2"],
  "translation": "Arabic translation of the word",
  "partOfSpeech": "noun/verb/adjective/etc"
}
Return ONLY valid JSON, no markdown formatting.`;

    const raw = await this.geminiService.generate(prompt);
    try {
      const cleaned = raw
        .replace(/```json?/gi, '')
        .replace(/```/g, '')
        .trim();
      return JSON.parse(cleaned);
    } catch {
      return {
        word,
        definition: raw,
        examples: [],
        translation: '',
        pronunciation: '',
        partOfSpeech: '',
      };
    }
  }

  async saveWord(
    userId: string,
    data: {
      word: string;
      definition: string;
      examples?: string;
      translation?: string;
      language?: string;
      contextSentence?: string;
    },
  ) {
    const entry = this.vocabRepository.create({ userId, ...data });
    return this.vocabRepository.save(entry);
  }

  async listWords(userId: string) {
    return this.vocabRepository.find({
      where: { userId },
      order: { savedAt: 'DESC' },
    });
  }

  async deleteWord(userId: string, id: string) {
    const word = await this.vocabRepository.findOne({ where: { id, userId } });
    if (!word) throw new NotFoundException('Vocabulary word not found');
    return this.vocabRepository.remove(word);
  }
}
